const input = ($json && typeof $json === 'object') ? $json : {};
const body = (input.body && typeof input.body === 'object') ? input.body : input;

const toText = (value) => {
  if (value === null || value === undefined) return '';
  if (Array.isArray(value)) {
    return value.map(toText).filter(Boolean).join(', ');
  }
  return String(value).replace(/\s+/g, ' ').trim();
};

const toLower = (value) => toText(value).toLowerCase();

const pick = (...keys) => {
  for (const key of keys) {
    if (Object.prototype.hasOwnProperty.call(body, key)) {
      const value = toText(body[key]);
      if (value) return value;
    }
  }
  return '';
};

const normalizeTimeline = (value) => {
  const raw = toLower(value);
  if (!raw) return 'non-renseigne';
  if (raw.includes('urgent') || raw.includes('1 mois') || raw.includes('moins')) return 'urgent';
  if (raw.includes('1-3') || (raw.includes('1') && raw.includes('3') && raw.includes('mois'))) return '1-3-mois';
  if (raw.includes('3-6') || (raw.includes('3') && raw.includes('6') && raw.includes('mois'))) return '3-6-mois';
  if (raw.includes('pas') || raw.includes('presse')) return 'pas-presse';
  return 'autre';
};

const firstName = pick('prenom', 'firstName', 'firstname', 'first_name', 'name');
const lastName = pick('nom', 'lastName', 'lastname', 'last_name', 'surname');
const email = toLower(pick('email', 'mail', 'emailAddress', 'email_address'));
const phone = pick('telephone', 'phone', 'tel', 'mobile', 'numero');
const company = pick('entreprise', 'company', 'societe', 'business_name');
const sector = pick('secteur', 'secteur_activite', 'industry', 'domaine');
const website = pick('site_actuel', 'site', 'website', 'url');
const needs = pick('besoins', 'besoin', 'project_need', 'project');
const timelineRaw = pick('delai', 'timeline', 'deadline', 'timeframe');
const note = pick('message', 'note', 'notes', 'details');

const knownKeys = new Set([
  'prenom', 'firstName', 'firstname', 'first_name', 'name',
  'nom', 'lastName', 'lastname', 'last_name', 'surname',
  'email', 'mail', 'emailAddress', 'email_address',
  'telephone', 'phone', 'tel', 'mobile', 'numero',
  'entreprise', 'company', 'societe', 'business_name',
  'secteur', 'secteur_activite', 'industry', 'domaine',
  'site_actuel', 'site', 'website', 'url',
  'besoins', 'besoin', 'project_need', 'project',
  'delai', 'timeline', 'deadline', 'timeframe',
  'message', 'note', 'notes', 'details'
]);

const extras = {};
Object.keys(body || {}).forEach((key) => {
  if (!knownKeys.has(key)) {
    extras[key] = toText(body[key]);
  }
});

const hasMeaningfulData = [firstName, lastName, email, phone, company, sector, website, needs, timelineRaw, note].some(Boolean);
const receivedAt = new Date().toISOString();
const reference = `kit-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const responseBody = hasMeaningfulData
  ? {
      status: 'success',
      message: 'Merci, votre demande de kit gratuit est bien recue. Nous revenons vers vous sous 24h ouvrables.',
      data: { source: 'kit-arpenteur', reference, receivedAt }
    }
  : {
      status: 'error',
      message: 'Nous n\'avons pas pu lire correctement votre formulaire. Verifiez les champs principaux puis reessayez.',
      data: { source: 'kit-arpenteur', reference, receivedAt }
    };

return [{
  json: {
    source: 'kit-arpenteur',
    reference,
    receivedAt,
    normalizedPayload: {
      firstName,
      lastName,
      email,
      phone,
      company,
      sector,
      website,
      needs,
      timeline: normalizeTimeline(timelineRaw),
      timelineRaw: toText(timelineRaw),
      note,
      extras
    },
    rawPayload: body,
    responseCode: hasMeaningfulData ? 200 : 422,
    responseBody
  }
}];
